# Simulated user store (in production, use a proper database with hashed passwords)
USERS_DB = {}


def _hash_password(password: str, salt: str) -> str:
    """Hash a password with a salt using PBKDF2."""
    return hashlib.pbkdf2_hmac(
        "sha256", password.encode("utf-8"), salt.encode("utf-8"), 310000
    ).hex()


def register_user(username: str, password: str) -> bool:
    """Register a user with a securely hashed password."""
    if username in USERS_DB:
        return False
    salt = secrets.token_hex(16)
    password_hash = _hash_password(password, salt)
    USERS_DB[username] = {"salt": salt, "password_hash": password_hash}
    return True


def verify_user(username: str, password: str) -> bool:
    """Verify user credentials using constant-time comparison."""
    user = USERS_DB.get(username)
    if user is None:
        # Perform a dummy hash to prevent timing attacks
        _hash_password(password, "dummy_salt_value_1234")
        return False
    computed_hash = _hash_password(password, user["salt"])
    return hmac.compare_digest(computed_hash, user["password_hash"])


# --- Allowed redirect hosts (whitelist) ---
ALLOWED_HOSTS = {
    "localhost",
    "127.0.0.1",
}

# Add configured server name if available
_server_name = os.environ.get("SERVER_NAME")
if _server_name:
    ALLOWED_HOSTS.add(_server_name.split(":")[0])


def is_safe_redirect_url(target: str) -> bool:
    """
    Validate that a redirect URL is safe (relative to our host or in the whitelist).
    Prevents open redirect vulnerabilities.
    """
    if not target:
        return False

    # Reject URLs with control characters or newlines (header injection)
    if re.search(r"[\r\n\x00]", target):
        return False

    # Reject javascript:, data:, vbscript: schemes
    stripped = target.strip().lower()
    if stripped.startswith(("javascript:", "data:", "vbscript:", "//", "\\")):
        return False

    # Parse the target URL
    parsed = urlparse(target)

    # Allow relative URLs (no scheme and no netloc)
    if not parsed.scheme and not parsed.netloc:
        # Ensure it starts with / to avoid protocol-relative URLs
        if target.startswith("/") and not target.startswith("//"):
            return True
        return False

    # For absolute URLs, check scheme and host
    if parsed.scheme not in ("http", "https"):
        return False

    host = parsed.hostname
    if host is None:
        return False

    return host in ALLOWED_HOSTS


def get_safe_redirect_target():
    """
    Retrieve and validate the redirect target from the 'next' parameter
    or the referrer header.
    """
    # Check 'next' query parameter first
    target = request.args.get("next") or request.form.get("next")

    if target and is_safe_redirect_url(target):
        return target

    # Fallback to referrer if safe
    referrer = request.referrer
    if referrer and is_safe_redirect_url(referrer):
        return referrer

    return None


def redirect_to_target(fallback: str = None):
    """
    Redirect to the validated target URL or a safe fallback.
    """
    if fallback is None:
        fallback = url_for("dashboard")

    target = get_safe_redirect_target()
    if target:
        # Use urljoin to properly resolve relative URLs
        safe_url = urljoin(request.host_url, target)
        # Double-check the joined URL is still safe
        if is_safe_redirect_url(safe_url) or is_safe_redirect_url(target):
            return redirect(target)

    return redirect(fallback)


def login_required(f):
    """Decorator to require authentication for a view."""

    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "user" not in session:
            # Store the intended destination in the 'next' parameter
            return redirect(url_for("login", next=request.full_path))
        return f(*args, **kwargs)

    return decorated_function


# --- CSRF Protection ---
def generate_csrf_token():
    """Generate a CSRF token and store it in the session."""
    if "_csrf_token" not in session:
        session["_csrf_token"] = secrets.token_hex(32)
    return session["_csrf_token"]


def validate_csrf_token():
    """Validate the CSRF token from the form submission."""
    token = session.get("_csrf_token")
    form_token = request.form.get("_csrf_token")
    if not token or not form_token:
        return False
    return hmac.compare_digest(token, form_token)


app.jinja_env.globals["csrf_token"] = generate_csrf_token


