# --- Routes ---
@app.route("/")
def index():
    if "user" in session:
        return redirect(url_for("dashboard"))
    return redirect(url_for("login"))


@app.route("/login", methods=["GET", "POST"])
def login():
    # If already logged in, redirect to target or dashboard
    if "user" in session:
        return redirect_to_target(fallback=url_for("dashboard"))

    if request.method == "POST":
        # Validate CSRF token
        if not validate_csrf_token():
            abort(403)

        username = request.form.get("username", "").strip()
        password = request.form.get("password", "")

        # Basic input validation
        if not username or not password:
            flash("Username and password are required.", "error")
            return render_template_string(
                LOGIN_TEMPLATE,
                next_url=request.form.get("next", ""),
            ), 400

        if len(username) > 150 or len(password) > 1024:
            flash("Invalid input.", "error")
            return render_template_string(
                LOGIN_TEMPLATE,
                next_url=request.form.get("next", ""),
            ), 400

        if verify_user(username, password):
            # Regenerate session to prevent session fixation
            session.clear()
            session["user"] = username
            session.permanent = True

            flash("Login successful!", "success")
            return redirect_to_target(fallback=url_for("dashboard"))
        else:
            flash("Invalid username or password.", "error")
            return render_template_string(
                LOGIN_TEMPLATE,
                next_url=request.form.get("next", ""),
            ), 401

    # GET request
    next_url = request.args.get("next", "")
    # Sanitize next_url for display in the template
    if not is_safe_redirect_url(next_url):
        next_url = ""

    return render_template_string(LOGIN_TEMPLATE, next_url=next_url)


@app.route("/logout", methods=["POST"])
def logout():
    if not validate_csrf_token():
        abort(403)
    session.clear()
    flash("You have been logged out.", "success")
    return redirect(url_for("login"))


